def assess(record: dict) -> str:
    required = {'sensitive_action', 'network', 'filesystem', 'checkpoint', 'replayed_effects', 'case_id', 'approval_present', 'approval_required'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + missing[0]
    meets = not (record["network"] == "open" or not record["approval_present"] or record["replayed_effects"] > 0)
    return "PASS" if meets else 'SANDBOX_AND_STOP'

